import{c as a,Q as s,j as o,m as t}from"./chunks/framework.rlpw0eGz.js";const p="/blogs/2026-05-15/desktop-settings.gif",r="/blogs/2026-05-15/display-browser.gif",l="/blogs/2026-05-15/display-terminal.gif",w=JSON.parse('{"title":"提供桌面，我们可以做到更多 - 介绍Memoh的桌面电脑功能","description":"","frontmatter":{"title":"提供桌面，我们可以做到更多 - 介绍Memoh的桌面电脑功能","author":"Ran Chen"},"headers":[],"relativePath":"blogs/2026-05-15.md","filePath":"blogs/2026-05-15.md","lastUpdated":1778786322000}'),i={name:"blogs/2026-05-15.md"};function n(d,e,c,h,m,b){return s(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="提供桌面-我们可以做到更多-介绍memoh的桌面电脑功能" tabindex="-1">提供桌面，我们可以做到更多 - 介绍Memoh的桌面电脑功能 <a class="header-anchor" href="#提供桌面-我们可以做到更多-介绍memoh的桌面电脑功能" aria-label="Permalink to &quot;提供桌面，我们可以做到更多 - 介绍Memoh的桌面电脑功能&quot;">​</a></h1><p>很多 Agent 在文字和命令行里表现不错，遇到真实网页和图形界面时就容易卡住。</p><p>比如登录后台时弹出新窗口；上传文件时需要处理文件选择器；有些按钮只有页面渲染出来以后才知道在哪里；同一个页面在 headless browser 里正常，在真实 Chrome 里会被样式、权限或弹窗卡住。用户问“你帮我看看这个页面现在是什么状态”时，只读 HTML 经常不够。</p><p>所以我们给 Memoh 的 bot workspace 加了桌面功能。</p><p>每个支持 Display 的 workspace container 都可以启动一个可见的图形桌面。里面有窗口管理器、终端、headed Chrome/Chromium 浏览器。用户可以在 Web UI 里看到它，bot 也可以通过工具操作它。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>本文里的“桌面电脑功能”指 bot workspace 里的可见桌面。Memoh 的 Electron 桌面客户端负责本地应用体验、托管本地 server、启动嵌入式 Qdrant 和 CLI，属于另一层。</p></div><h2 id="为什么-agent-需要桌面" tabindex="-1">为什么 Agent 需要桌面 <a class="header-anchor" href="#为什么-agent-需要桌面" aria-label="Permalink to &quot;为什么 Agent 需要桌面&quot;">​</a></h2><p>命令行适合确定性的工作：读写文件、跑测试、执行脚本、调用 API。Headless browser 也很强，适合自动化、爬取、页面测试。</p><p>很多真实任务还需要看到渲染后的界面。</p><p>真实网页里有登录态、弹窗、拖拽、canvas、复杂组件、权限提示、文件选择器，还有很多只能从画面上判断的状态。用户也经常需要看 bot 正在做什么，必要时自己接手点一下。</p><p>桌面功能解决两个具体问题：bot 可以操作一个真实可见的浏览器；用户可以看到同一个画面。</p><h2 id="workspace-display-跑在容器里的桌面" tabindex="-1">Workspace Display：跑在容器里的桌面 <a class="header-anchor" href="#workspace-display-跑在容器里的桌面" aria-label="Permalink to &quot;Workspace Display：跑在容器里的桌面&quot;">​</a></h2><p>Memoh 的 workspace 桌面运行在 bot 的 container 里，不直接控制用户的 Mac、Windows 或 Linux 主机桌面。它的文件、命令、网络和工具权限都跟着这个 workspace 走。</p><p>当 bot 启用 Workspace Display 后，bridge 会在容器里启动一套图形运行时：</p><ul><li><code>Xvnc</code> 提供 X11 显示服务和 RFB 输入输出通道</li><li><code>xfce4</code> / <code>xfwm4</code> / <code>twm</code> 等组件提供桌面或窗口管理能力</li><li><code>xterm</code> 打开一个默认终端，工作目录指向 workspace</li><li>Chrome/Chromium 以 headed 模式启动，并暴露本地 CDP 端口</li></ul><p>对用户来说，这个桌面会出现在 Web UI 的 Display pane 里。前端通过 WebRTC 连接后端 display service，看到的是 bot workspace 的实时画面；键盘和鼠标输入也会被转发回容器。</p><p>对 bot 来说，这是一个可以操作的运行环境。</p><p><img src="'+p+`" alt="在 Memoh 里打开 workspace display 的 demo"></p><p><em>Display pane 里展示的是 bot workspace 的图形桌面，浏览器就在这个桌面里运行。</em></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bot workspace container</span></span>
<span class="line"><span>├── files and commands</span></span>
<span class="line"><span>├── bridge process</span></span>
<span class="line"><span>├── Xvnc display (:99)</span></span>
<span class="line"><span>├── terminal</span></span>
<span class="line"><span>└── headed Chrome / Chromium</span></span>
<span class="line"><span>    └── CDP on 127.0.0.1:9222</span></span></code></pre></div><p>用户打开 Display pane 看到浏览器停在哪个页面，bot 通过 Browser Use 操作的也是这个浏览器。</p><h2 id="browser-use-操作同一个可见浏览器" tabindex="-1">Browser Use：操作同一个可见浏览器 <a class="header-anchor" href="#browser-use-操作同一个可见浏览器" aria-label="Permalink to &quot;Browser Use：操作同一个可见浏览器&quot;">​</a></h2><p>如果目标在网页里，Memoh 会优先让 bot 使用 Browser Use。</p><p>Browser Use 通过 Chrome DevTools Protocol（CDP）连接 workspace 里的 Chrome/Chromium。这个浏览器以 headed 模式运行，会显示在 Display pane 里。</p><p>Memoh 给 agent 暴露了几个工具：</p><p><img src="`+r+'" alt="在 Display pane 里操作有头浏览器的 demo"></p><p><em>Display pane 里打开的是 workspace 里的 Chrome。用户看到的页面和 bot 操作的是同一个浏览器状态。</em></p><p><strong><code>browser_observe</code></strong>：观察当前浏览器状态。它可以读取可交互元素快照、正文内容、标题、URL、HTML，也可以截图或做带标注的截图。</p><p><strong><code>browser_action</code></strong>：执行浏览器动作，比如打开 URL、点击、填写输入框、按键、滚动、上传文件、切换标签页。</p><p><strong><code>browser_remote_session</code></strong>：给需要写 Playwright 或 CDP 脚本的场景用。脚本可以连接同一个 workspace Chrome，不需要重新开一个浏览器。</p><p>用户看到的页面、bot 读取的页面、工具操作的页面，都来自同一个浏览器状态。bot 做到一半卡住时，用户可以看见；用户手动处理完登录或权限提示后，bot 可以继续。</p><h2 id="computer-use-当网页语义不够用" tabindex="-1">Computer Use：当网页语义不够用 <a class="header-anchor" href="#computer-use-当网页语义不够用" aria-label="Permalink to &quot;Computer Use：当网页语义不够用&quot;">​</a></h2><p>Browser Use 适合网页里的 DOM、表单、按钮和导航。但有些界面不在 CDP 能理解的范围里。</p><p>比如系统文件选择器、浏览器原生权限弹窗、崩掉的页面、非浏览器 GUI 应用，或者只能通过坐标和像素处理的状态。这时候就需要 Computer Use。</p><p>Computer Use 的流程更直接：先截图，再移动鼠标、点击、拖拽、滚动、输入文字、按快捷键。它走显示层输入输出，不依赖浏览器 DOM。</p><p>很多自动化会卡在这些小动作上：看一眼屏幕，点按钮，按 Esc，重新聚焦窗口。Computer Use 就是用来处理这些情况的。</p><p>Memoh 的策略是：能用 Browser Use 就用 Browser Use，因为它更稳定、语义更清楚；CDP 到不了的时候，再退到 Computer Use。</p><h2 id="display-pane-让用户也在场" tabindex="-1">Display Pane：让用户也在场 <a class="header-anchor" href="#display-pane-让用户也在场" aria-label="Permalink to &quot;Display Pane：让用户也在场&quot;">​</a></h2><p>桌面功能也应该给用户看。</p><p>在 Memoh 的 Web UI 里，workspace 区域可以打开 chat、draft、file、terminal，也可以打开 display tab。Display pane 会检查桌面运行时是否准备好；如果缺少依赖，它会通过后端的 prepare 流程安装或配置需要的桌面、VNC、浏览器和字体组件。</p><p>连接成功后，用户能看到当前 workspace 的主显示器。</p><p><img src="'+l+'" alt="在 workspace display 里打开终端的 demo"></p><p><em>同一个 Display session 里可以看到浏览器、终端和其它图形界面。</em></p><p>这让很多工作流变得更顺手：</p><ul><li>bot 帮你调试 Web UI，你可以直接看它点到了哪里</li><li>bot 打开后台页面，你可以手动处理一次登录，然后让它继续</li><li>bot 复现一个视觉 bug，你可以确认它看到的状态和你看到的一样</li><li>bot 操作不确定的界面时，你可以随时接管鼠标键盘</li></ul><p>这样做的好处很简单：bot 不需要把所有状态都描述出来，用户可以直接看。</p><h2 id="为什么不只用-headless-playwright" tabindex="-1">为什么不只用 Headless Playwright <a class="header-anchor" href="#为什么不只用-headless-playwright" aria-label="Permalink to &quot;为什么不只用 Headless Playwright&quot;">​</a></h2><p>Headless Playwright 当然有用。我们也不打算用桌面替代它。</p><p>它们的分工大概是这样：</p><table tabindex="0"><thead><tr><th>能力</th><th>适合做什么</th><th>局限</th></tr></thead><tbody><tr><td>命令行工具</td><td>文件、代码、测试、构建、脚本任务</td><td>看不到图形状态</td></tr><tr><td>Headless browser</td><td>快速网页自动化、批量测试、确定性脚本</td><td>用户看不到运行过程，遇到真实登录/弹窗/视觉状态时容易断层</td></tr><tr><td>Browser Use</td><td>操作可见 Chrome、处理网页、表单、导航、截图</td><td>主要覆盖浏览器内的页面状态</td></tr><tr><td>Computer Use</td><td>原生弹窗、非浏览器 GUI、坐标级恢复</td><td>语义少，动作需要更谨慎</td></tr><tr><td>Display Pane</td><td>用户观察、接管、协作确认</td><td>需要 workspace 支持图形运行时</td></tr></tbody></table><p>Headless browser 适合跑脚本和批量任务。Workspace Display 适合处理需要用户看到画面的任务。</p><h2 id="权限和隔离" tabindex="-1">权限和隔离 <a class="header-anchor" href="#权限和隔离" aria-label="Permalink to &quot;权限和隔离&quot;">​</a></h2><p>这个桌面不会接管用户电脑。</p><p>Memoh 的桌面跑在 workspace container 里。它的文件系统、进程、网络和工具权限仍然跟着 bot 的 workspace 走。Web UI 负责显示这个容器桌面，并把用户输入转发进去。</p><p>它只操作 workspace 桌面，用户的系统桌面不在这个通道里。</p><p>对于 trusted local workspace，Memoh 会更谨慎：这类 workspace 本来就运行在宿主机权限下，Display pane 默认不作为普通容器桌面暴露。桌面能力优先服务的是可隔离、可销毁、可重建的 container workspace。</p><h2 id="可以做到更多" tabindex="-1">可以做到更多 <a class="header-anchor" href="#可以做到更多" aria-label="Permalink to &quot;可以做到更多&quot;">​</a></h2><p>有了桌面以后，很多过去不好处理的任务会简单一些。</p><p>bot 可以打开本地 Web 服务，看页面、点按钮、截图、定位问题；可以进入 SaaS 控制台，按用户确认过的步骤配置项目；可以在可见浏览器里处理 OAuth 流程，少一些对重定向和页面状态的猜测；也可以在遇到不稳定 UI 时，把当前画面发出来，让用户判断下一步。</p><p>用户也不用猜 bot 在后台做了什么。打开 Display pane 就能看到。</p><h2 id="未来计划" tabindex="-1">未来计划 <a class="header-anchor" href="#未来计划" aria-label="Permalink to &quot;未来计划&quot;">​</a></h2><p>桌面电脑功能现在已经能用，但离“顺手”还有不少细节。接下来我们会重点处理这些地方：</p><ul><li><strong>第一次打开要少折腾</strong>：有些 workspace 镜像缺字体，有些缺浏览器，有些包管理器源很慢。Display prepare 已经能处理一部分情况，但失败时还应该给出更明确的原因和修复方式。</li><li><strong>bot 做过什么要能看懂</strong>：一次点击、一次输入、一次截图，应该和对应的工具调用放在一起看。用户不需要翻日志猜它刚才点了哪里。</li><li><strong>用户接管以后，bot 要会继续</strong>：登录、两步验证、权限确认这类步骤经常需要人处理。我们希望 bot 能明确停在这里，等用户处理完，再从当前页面状态接着做。</li><li><strong>会话权限要更细</strong>：谁能看桌面、谁能接管键鼠、截图能不能发到当前对话、远程 CDP 连接多久过期，这些都应该能配置。</li><li><strong>复杂界面要更稳</strong>：canvas、拖拽、富文本编辑器、文件上传、多窗口切换，这些场景会继续补测试和工具能力。</li></ul><p>我们做 Memoh 的一个基本判断是：聊天框适合沟通，命令行适合执行，记忆系统适合长期上下文，桌面适合需要看画面和操作界面的任务。</p><p>给 bot 一个 workspace 桌面以后，它可以打开页面、看状态、点按钮、试流程，再把结果告诉用户。</p>',65)])])}const g=a(i,[["render",n]]);export{w as __pageData,g as default};
